  buildMessage msg =
    V.foldl' (\acc v -> acc <> encodeFieldMessage 1 v) mempty msg.historyEvents

instance MessageSize History where
  messageSize msg =
    (V.foldl' (\acc v -> acc + fieldMessageSize 1 (messageSize v)) 0 msg.historyEvents)

